sys_security_acl.script:
(function evaluateRule(current, table) {
  // Allow any authenticated user to read Employee KB articles
  // Check if article belongs to Employee KB
  if (!current) return false;

  var kbGr = new GlideRecord('kb_knowledge_base');
  if (kbGr.get('name', 'Employee Knowledge Base')) {
    var kbSysId = kbGr.getUniqueValue();
    if (current.getValue('kb_knowledge_base') === kbSysId) {
      return true;
    }
  }

  return false;
})(current, table);
